/// <summary>
/// Controller class for the quota contract line generation process for the ETGSPAIN model.
/// </summary>
class ETGSPAINPurchSalesAgreementQuotaDialogController extends SysOperationServiceController
{
}

Method.Source:
/// <summary>
/// Method to generate a new instance of the class.
/// </summary>
protected void new()
{
    super(classStr(ETGSPAINPurchSalesAgreementQuotaDialogService), methodStr(ETGSPAINPurchSalesAgreementQuotaDialogService, process), SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// Constructor method for the class.
/// </summary>
/// <param name = "_executionMode">Execution mode type for the operation.</param>
/// <returns>Returns an instance of <c>ETGSPAINPurchSalesAgreementQuotaDialogController</c>.</returns>
public static ETGSPAINPurchSalesAgreementQuotaDialogController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGSPAINPurchSalesAgreementQuotaDialogController controller;

    controller = new ETGSPAINPurchSalesAgreementQuotaDialogController();
    controller.parmExecutionMode(_executionMode);

    return controller;
}

/// <summary>
/// Method <c>defaultCaption</c> to display the process description.
/// </summary>
/// <returns>Returns the description of the process.</returns>
public ClassDescription defaultCaption()
{
    return "@ETGSPAINLabels:AgreementQuota";
}

/// <summary>
/// Main method, invoked from the MenuItem to execute the service.
/// </summary>
/// <param name = "_args">Arguments passed to the process.</param>
public static void main(Args _args)
{
    ETGSPAINPurchSalesAgreementQuotaDialogController controller;
    ETGSPAINPurchSalesAgreementQuotaDialogContract   contract;
    AgreementHeader                             agreementHeader = _args.record();

    controller = ETGSPAINPurchSalesAgreementQuotaDialogController::construct();
    controller.parmArgs(_args);
    controller.showBatchTab(false);
    controller.parmLoadFromSysLastValue(false);

    contract = controller.getDataContractObject('_contract');
    contract.parmAgreementHeaderRecId(agreementHeader.RecId);
    contract.parmQuotaFromDate(agreementHeader.ETGSPAINPurchExecutionFromDate);
    contract.parmQuotaToDate(agreementHeader.ETGSPAINPurchExecutionDueDate);        

    if (agreementHeader.ETGSPAINPurchHasAgreementQuotas)
    {
        controller.parmShowDialog(false);
    }

    controller.startOperation();
}
